/*
输入n和m
如果n<2m
	输出Error! 
循环遍历1~n
	输入p[i].val
	p[i].l=i-1
	p[i].r=i+1
	q.push ({p[i].val,i})
循环遍历1~m 
	while循环vis[q.top()]
		q.pop()
	进行反悔贪心
输出结果 
*/
#include <bits/stdc++.h>
#define int long long
using namespace std;
struct Edge {
	int val, l, r;
};
Edge p[200005];
struct Node {
	int val, id;
	bool operator <(Node it) const {
		return val < it.val;
	}
};
int n, m, ans;
bool vis[200005];
priority_queue <Node> q;
void Del (int x) {
	p[x].l = p[p[x].l].l;
	p[x].r = p[p[x].r].r;
	p[p[x].l].r = x;
	p[p[x].r].l = x;
}
signed main () {
	cin >> n >> m;
	if (n < 2 * m) {
		cout << "Error!";
		return 0;
	}
	for (int i = 1; i <= n; i++) {
		cin >> p[i].val;
		p[i].l = i - 1;
		p[i].r = i + 1;
		q.push ((Node){p[i].val, i});
	}
	p[1].l = n, p[n].r = 1;
	for (int i = 1; i <= m; i++) {
		while (vis[q.top().id]) {
			q.pop();
		}
		Node now = q.top();
		q.pop();
		ans += now.val;
		vis[p[now.id].l] = vis[p[now.id].r] = 1;
		p[now.id].val = p[p[now.id].l].val + p[p[now.id].r].val - p[now.id].val;
		q.push((Node){p[now.id].val, now.id});
		Del (now.id);
	}
	cout << ans;
	return 0;
}
